import React, { useEffect, useState } from 'react';
import adminService from '../services/adminService';
function AdminDashboard(){
  const [users,setUsers]=useState([]); const [logs,setLogs]=useState([]);
  useEffect(()=>{ (async()=>{ try{ const u=await adminService.getUsers(); setUsers(u); const lg=await adminService.getLogs(); setLogs(lg); }catch(e){ console.error(e); } })(); },[]);
  const del=async(id)=>{ if(!confirm('Delete user?')) return; await adminService.deleteUser(id); setUsers(users.filter(u=>u.id!==id)); };
  return (
    <div className="p-6 grid md:grid-cols-2 gap-6">
      <div className="bg-white p-4 rounded">
        <h3 className="font-bold mb-2">Users</h3>
        <table className="w-full"><thead><tr><th>ID</th><th>Name</th><th>Email</th><th>Role</th><th>Action</th></tr></thead>
        <tbody>{users.map(u=>(<tr key={u.id}><td>{u.id}</td><td>{u.name}</td><td>{u.email}</td><td>{u.role}</td><td><button onClick={()=>del(u.id)} className="bg-red-500 text-white px-2 py-1 rounded">Delete</button></td></tr>))}</tbody></table>
      </div>
      <div className="bg-white p-4 rounded">
        <h3 className="font-bold mb-2">Logs</h3>
        <div style={{maxHeight:400, overflow:'auto'}}><table className="w-full"><thead><tr><th>ID</th><th>User</th><th>Action</th><th>File</th><th>Status</th></tr></thead><tbody>{logs.map(l=>(<tr key={l.id}><td>{l.id}</td><td>{l.user_email}</td><td>{l.action}</td><td>{l.file_id}</td><td>{l.status}</td></tr>))}</tbody></table></div>
      </div>
    </div>
  );
}
export default AdminDashboard;
